#!/bin/bash
PROJECT_ROOT='/opt'
VENV_PATH="$PROJECT_ROOT/venv"
DB_NAME='password_manager'
DB_USER='postgres'
DB_PASS='S1st3mas'
ADMIN_EMAIL='admin@admin.com'
ADMIN_PASS='admin12345'
APP_PORT=8000 # Internal port for Uvicorn
echo '>>> Starting V5 (Self-Contained)...'

echo ">>> Configuring System Timezone (America/Bogota)..."
timedatectl set-timezone America/Bogota || true
if command -v yum >/dev/null 2>&1; then
    echo ">>> Enabling NTP synchronization (Chrony)..."
    yum install -y chrony >/dev/null 2>&1 || true
    systemctl enable --now chronyd >/dev/null 2>&1 || true
fi
date

setsebool -P httpd_can_network_connect 1 || true
dnf install -y oracle-epel-release-el9
dnf install -y python39 python3-pip python3-devel gcc libffi-devel openssl-devel git firewalld postgresql-server postgresql-contrib nginx certbot python3-certbot-nginx -y
rm -f /etc/nginx/conf.d/default.conf
systemctl enable --now firewalld
firewall-cmd --permanent --add-service=http --add-service=https
firewall-cmd --permanent --add-port=8080/tcp
firewall-cmd --reload
if [ ! -f /var/lib/pgsql/data/PG_VERSION ]; then
    postgresql-setup --initdb || sudo -u postgres /usr/bin/initdb -D /var/lib/pgsql/data
fi
sed -i 's/ident/md5/g' /var/lib/pgsql/data/pg_hba.conf
systemctl restart postgresql
systemctl enable postgresql
sleep 3
cd /tmp
sudo -u postgres psql -c "ALTER USER postgres PASSWORD '$DB_PASS';"
sudo -u postgres psql -c "CREATE DATABASE $DB_NAME;" || true
echo '>>> Extracting code...'
mkdir -p $PROJECT_ROOT
cd $PROJECT_ROOT
base64 -d <<'EOF_CODE' > code.tar.gz

EOF_CODE
tar -xzf code.tar.gz
rm code.tar.gz

echo '>>> Applying hardened rotation and permission patches...'
python3 -c "
import os
def patch_file(path, replacements):
    if not os.path.exists(path): return
    with open(path, 'r') as f: c = f.read()
    for old, new in replacements:
        if old in c and new.split('\n')[0] not in c:
            c = c.replace(old, new)
    with open(path, 'w') as f: f.write(c)

# Patch credential_service.py
patch_file('app/services/credential_service.py', [
    ('from app.models.activity_log import ActivityEventType', 'from app.models.activity_log import ActivityEventType\nfrom pathlib import Path'),
    ('ActivityLogService(self.db).log(ActivityEventType.DELETE_CREDENTIAL, True, current_user.id, f\"Eliminada credencial: {name} (ID: {credential_id})\")\n\n    ', 'ActivityLogService(self.db).log(ActivityEventType.DELETE_CREDENTIAL, True, current_user.id, f\"Eliminada credencial: {name} (ID: {credential_id})\")\n\n    def _verify_permission(self, credential_id: int, user: User, required_level: str) -> bool:\n        if user.is_admin: return True\n        from app.models.credential import Credential\n        cred = self.db.scalar(select(Credential).where(Credential.id == credential_id))\n        if not cred: return False\n        if cred.created_by == user.id: return True\n        from app.models.shared_credential import SharedCredential\n        share = self.db.scalar(select(SharedCredential).where(SharedCredential.credential_id == credential_id, SharedCredential.to_user_id == user.id))\n        if not share: return False\n        levels = {\"read\": 0, \"edit\": 1, \"share\": 2, \"all\": 3}\n        return levels.get(share.permission_level, 0) >= levels.get(required_level, 0)\n\n    '),
    ('def update_credential(self, company_id: int, credential_id: int, payload: CredentialUpdate, current_user: User) -> Credential:\n        stmt = select(Credential).options(selectinload(Credential.services)).where(Credential.id == credential_id)\n        credential = self.db.scalar(stmt)\n        if not credential: raise ValueError(\"Credencial no encontrada\")\n        if not current_user.is_admin and credential.created_by != current_user.id:', 'def update_credential(self, company_id: int, credential_id: int, payload: CredentialUpdate, current_user: User) -> Credential:\n        if not self._verify_permission(credential_id, current_user, \"edit\"): raise PermissionError(\"No tienes permisos suficientes (Nivel EDIT requerido)\")\n        stmt = select(Credential).options(selectinload(Credential.services)).where(Credential.id == credential_id)\n        credential = self.db.scalar(stmt)\n        if not credential: raise ValueError(\"Credencial no encontrada\")\n        if False: # Replaced by _verify_permission'),
    ('def rotate_password(self, company_id: int, credential_id: int, current_user: User, payload: CredentialRotate):\n        stmt = select(Credential).options(selectinload(Credential.services)).where(Credential.id == credential_id)\n        credential = self.db.scalar(stmt)\n        if not credential: raise ValueError(\"Credencial no encontrada\")', 'def rotate_password(self, company_id: int, credential_id: int, current_user: User, payload: CredentialRotate):\n        if not self._verify_permission(credential_id, current_user, \"all\"): raise PermissionError(\"No tienes permisos suficientes (Nivel ALL requerido)\")\n        stmt = select(Credential).options(selectinload(Credential.services)).where(Credential.id == credential_id)\n        credential = self.db.scalar(stmt)\n        if not credential: raise ValueError(\"Credencial no encontrada\")'),
    ('if payload.root_pass:', 'if payload.root_pass and credential.username != \"root\":'),
    ('elif credential.root_pass:', 'elif credential.username == \"root\":\n            root_pass = decrypt_credential_password(credential.password_encrypted)\n            root_pass_source = \"credential.password_encrypted (root priority)\"\n        elif credential.root_pass:')
])

# Patch shared_credential_service.py
patch_file('app/services/shared_credential_service.py', [
    ('if not self._can_manage(company_id, current_user):\n            raise PermissionError(\"Solo administradores pueden prestar credenciales\")', 'can_share = False\n        if current_user.is_admin or credential.created_by == current_user.id: can_share = True\n        else:\n            my_share = self.db.scalar(select(SharedCredential).where(SharedCredential.credential_id == credential_id, SharedCredential.to_user_id == current_user.id))\n            if my_share and my_share.permission_level in [\"share\", \"all\"]: can_share = True\n        if not can_share: raise PermissionError(\"No tienes permisos suficientes (Nivel SHARE requerido)\")')
])

# v204: Patch SharedCredentialAccessRead schema
patch_file('app/schemas/shared_credential.py', [
    ('os: Optional[str]\n    group_id: Optional[int]', 'group_name: Optional[str]')
])

# v204: Patch shared_credentials router
patch_file('app/routers/shared_credentials.py', [
    ('os=credential.os,\n            group_id=credential.group_id,', 'group_name=credential.group_name,'),
    ('os=credential.os,\n        group_id=credential.group_id,', 'group_name=credential.group_name,')
])

# v204: Patch credentials router (duplicates and return type)
patch_file('app/routers/credentials.py', [
    ('return CredentialRead.model_validate(credential, from_attributes=True)', 'return credential'),
    ('@router.delete(\"/groups/predefined/{name}\")\ndef delete_predefined_group(name: str, db: Session = Depends(get_db)):\n    from sqlalchemy import text\n    db.execute(text(\"DELETE FROM predefined_groups WHERE name = :name\"), {\"name\": name})\n    db.commit()\n    return {\"success\": True}', '')
])

# v204: Patch backup_service timezone crash
patch_file('app/services/backup_service.py', [
    ('trigger=CronTrigger(hour=self.settings.backup_daily_hour, minute=self.settings.backup_daily_minute)', 'trigger=CronTrigger(hour=self.settings.backup_daily_hour, minute=self.settings.backup_daily_minute, timezone=\"UTC\")'),
    ('minute=self.settings.backup_weekly_minute,', 'minute=self.settings.backup_weekly_minute, timezone=\"UTC\",')
])
"

python3.9 -m venv $VENV_PATH
$VENV_PATH/bin/pip install --upgrade pip
echo '>>> Installing all Python dependencies...'
$VENV_PATH/bin/pip install --only-binary=:all: cryptography bcrypt==3.2.0 paramiko
$VENV_PATH/bin/pip install fastapi uvicorn sqlalchemy "psycopg[binary]" "passlib[bcrypt]" "python-jose[cryptography]" python-dotenv pydantic-settings pycryptodome python-multipart email-validator apscheduler

cat <<EOF > $PROJECT_ROOT/.env
APP_NAME=Kristoff API
DEBUG=true
DB_DRIVER=postgresql+psycopg
DB_HOST=localhost
DB_PORT=5432
DB_USER=$DB_USER
DB_PASSWORD=$DB_PASS
DB_NAME=$DB_NAME
JWT_SECRET_KEY=kristoff_secret_key_fixed_32_chars
JWT_ALGORITHM=HS256
JWT_ACCESS_TOKEN_EXPIRE_MINUTES=60
BOOTSTRAP_ADMIN_EMAIL=$ADMIN_EMAIL
BOOTSTRAP_ADMIN_PASSWORD=$ADMIN_PASS
AUTO_CREATE_TABLES=true
EOF

# BOOTSTRAP: Create initial groups in DB
echo ">>> Bootstrapping initial groups..."
systemctl start postgresql
sleep 2
sudo -u postgres psql -d $DB_NAME -c "CREATE TABLE IF NOT EXISTS predefined_groups (id SERIAL PRIMARY KEY, name TEXT UNIQUE NOT NULL);"
sudo -u postgres psql -d $DB_NAME -c "INSERT INTO predefined_groups (name) VALUES ('Sistemas'), ('Desarrollo'), ('Infraestructura'), ('DBA'), ('Seguridad') ON CONFLICT DO NOTHING;"

cat <<EOF > /etc/systemd/system/kristoff.service
[Unit]
Description=Kristoff Backend Service
After=network.target postgresql.service
[Service]
User=root
WorkingDirectory=$PROJECT_ROOT
EnvironmentFile=$PROJECT_ROOT/.env
Environment=PYTHONPATH=$PROJECT_ROOT
ExecStart=$VENV_PATH/bin/uvicorn main:app --host 127.0.0.1 --port $APP_PORT
Restart=always
RestartSec=5
[Install]
WantedBy=multi-user.target
EOF

systemctl daemon-reload
systemctl stop kristoff || true
systemctl enable --now kristoff

echo '>>> Configuring automatic expiration (Crontab)...'
# Setup cron job to run every 5 minutes using the virtualenv python
CRON_JOB="*/5 * * * * $VENV_PATH/bin/python3 $PROJECT_ROOT/expiry_job.py >> /var/log/kristoff_expiry.log 2>&1"
(crontab -l 2>/dev/null | grep -v "expiry_job.py"; echo "$CRON_JOB") | crontab -
touch /var/log/kristoff_expiry.log
chmod 644 /var/log/kristoff_expiry.log

mkdir -p /etc/nginx/ssl /etc/nginx/conf.d
openssl req -x509 -nodes -days 365 -newkey rsa:2048 -keyout /etc/nginx/ssl/kristoff.key -out /etc/nginx/ssl/kristoff.crt -subj "/C=US/ST=State/L=City/O=Kristoff/OU=IT/CN=localhost"
cat <<EOF > /etc/nginx/conf.d/kristoff.conf
server {
    listen 80;
    server_name _;
    location / {
        return 301 https://\$host\$request_uri;
    }
}
server {
    listen 443 ssl default_server;
    listen 8080 ssl;
    server_name _;
    ssl_certificate /etc/nginx/ssl/kristoff.crt;
    ssl_certificate_key /etc/nginx/ssl/kristoff.key;
    error_page 497 https://\$host:\$server_port\$request_uri;
    location / {
        proxy_pass http://127.0.0.1:$APP_PORT;
        proxy_set_header Host \$host;
        proxy_set_header X-Real-IP \$remote_addr;
        proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \$scheme;
        proxy_read_timeout 300;
        proxy_connect_timeout 300;
    }
}
EOF
rm -f /etc/nginx/conf.d/default.conf || true
nginx -t && systemctl restart nginx
systemctl enable nginx

echo '>>> Checking backend status...'
sleep 5
STATUS=$(curl -k -s -o /dev/null -w "%{http_code}" https://localhost:8080/)
if [ "$STATUS" == "301" ] || [ "$STATUS" == "200" ] || [ "$STATUS" == "404" ]; then
    echo -e "\033[0;32mINSTALLATION COMPLETE (SUCCESS)!\033[0m"
    echo "------------------------------------------------"
    echo "URL:            https://$(hostname -I | awk '{print $1}'):8080"
    echo "Admin Email:    $ADMIN_EMAIL"
    echo "Admin Password: $ADMIN_PASS"
    echo "------------------------------------------------"
else
    echo -e "\033[0;31mERROR: Backend is not responding on 8080 (HTTP $STATUS)\033[0m"
    journalctl -u kristoff -n 20
fi


